import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";
import Card from "../components/Card";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const { gem_prediction, shape_prediction, image } = location.state || {};

  return (
    <>
      <Topnav />

      {/* Header Section */}
      <div className="relative flex flex-col items-center bg-gradient-to-r from-purple-600 via-purple-700 to-purple-600 pb-32">
        <p className="mt-24 text-4xl font-bold text-white text-center">
          Gem Analysis Results
        </p>

        {/* Circular Gem Image */}
        {image && (
          <div className="absolute -bottom-16 w-40 h-40 rounded-full overflow-hidden border-4 border-white shadow-xl">
            <img
              src={URL.createObjectURL(image)}
              alt="Gem"
              className="w-full h-full object-cover"
            />
          </div>
        )}
      </div>

      {/* Main Content */}
      <div className="max-w-5xl mx-auto px-6 pt-24 pb-16 space-y-12">
        {/* Result Card */}
        <div className="flex flex-col items-center gap-6">
          <Card
            title={gem_prediction}
            description={shape_prediction}
            imageUrl={image ? URL.createObjectURL(image) : ""}
          />
          <button
            onClick={() => navigate("/imageuploader")}
            className="mt-4 w-40 py-2.5 px-5 text-white bg-purple-800 rounded-full border border-gray-200 hover:bg-purple-700 hover:text-white transition duration-300 focus:outline-none focus:ring-4 focus:ring-purple-300"
          >
            Re-Analyze
          </button>
        </div>

        {/* Optional Additional Cards */}
        {/* <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <CardData />
        </div> */}
      </div>

      <Footer />
    </>
  );
}

export default Result;
